package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
)

func generateSessionToken() (string, error) {
	token := make([]byte, 32)
	if _, err := rand.Read(token); err != nil {
		return "", err
	}
	return base64.StdEncoding.EncodeToString(token), nil
}

func main() {
	sessionToken, err := generateSessionToken()
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Println(sessionToken)
	}
}